<script lang="ts">
  import { appearance } from "$lib/theme-runtime.svelte";

  let { class: klass = "" }: { class?: string } = $props();

  // Source of truth for the mark is src/lib/assets/lola-logo.svg — inlined here
  // (rather than <img>) so the cream fill can follow the flavor. The wordmark
  // ships cream (#EFEFE4) for a dark tile; in-app it sits on `bg-canvas`, dark
  // on Catppuccin's dark flavors but light on Latte, where cream would vanish.
  // So the cream mark becomes the brand ink `#22242F` on light flavors. The red
  // streaks + hair read on both, so they stay brand. Keep this file's paths in
  // sync with the asset if the logo changes.
  const fg = $derived(appearance.flavor.dark ? "#EFEFE4" : "#22242F");
